function Queue() {
  var queueItems = [];
  var working = false;
  function runNext() {
    if (working || queueItems.length === 0) return;
    working = true;
    var task = queueItems.shift();
    task(function () {
      working = false;
      runNext();
    });
  }
  return {
    push: function (task) {
      queueItems.push(task);
      runNext();
    },
  };
}

var log = [];
var q = Queue();
q.push(function (done) {
  log.push('task1 start');
  setTimeout(function () { log.push('task1 done'); done(); }, 10);
});
q.push(function (done) {
  log.push('task2 start');
  setTimeout(function () { log.push('task2 done'); done(); }, 10);
});

setTimeout(function () {
  console.log(log.join(', '));
}, 100);

