function DroppingQueue(max, worker) {
  var queueItems = [];
  var working = false;
  function runNext() {
    if (working || queueItems.length === 0) return;
    working = true;
    var item = queueItems.shift();
    worker(item, function () {
      working = false;
      runNext();
    });
  }
  return {
    push: function (item) {
      queueItems.push(item);
      if (queueItems.length > max) {
        var dropped = queueItems.shift();
        log.push('drop ' + dropped);
      }
      runNext();
    },
  };
}

var log = [];
var q = DroppingQueue(2, function (item, done) {
  log.push('start ' + item);
  setTimeout(function () {
    log.push('done ' + item);
    done();
  }, 10);
});

q.push('A');
q.push('B');
q.push('C');
q.push('D');

setTimeout(function () {
  console.log(log.join(', '));
}, 100);

